INSERT INTO `products` (`id`, `product_name`, `slug`, `product_code`, `category_id`, `product_type_id`, `style_id`, `gender`, `original_price`, `sale_price`, `purchase_price`, `note`, `material`, `information`, `short_description`, `quantity`, `track_inventory`, `allow_backorder`, `min_stock_alert`, `supplier_contact`, `import_link`, `thumbnail`, `is_active`, `published_at`, `deleted_at`, `created_at`, `updated_at`, `is_hidden`) VALUES
(1, 'POLO  BURBERRY', 'polo-burberry-ao-001', 'AO_001', 1, 1, 1, 'Unisex', 340000.00, 269000.00, 190000.00, 'Đức buôn', 'Cotton, Mềm Mịn', 'Mô tả bán hàng\r\n\r\nPOLO BBR – BẢN MỚI NHẤT 2026\r\n\r\nHàng mới về cực đẹp cho anh em bán Tết 🔥\r\nThiết kế đơn giản – basic – sang xịn, dễ mặc, dễ phối đồ nên cực kỳ dễ bán.\r\n\r\n⚜️ Điểm nổi bật:\r\n\r\nForm polo nam chuẩn đẹp\r\n\r\nTúi ngực da nổi bật tạo điểm nhấn sang trọng\r\n\r\nPhong cách basic nam tính, mặc đi chơi – đi làm đều hợp\r\n\r\nChất vải mềm mịn, thoáng mát, mặc cực thoải mái\r\n\r\n⚜️ Màu sắc:\r\n\r\nTrắng\r\n\r\nĐen\r\n\r\nXanh navy\r\n\r\nXanh rêu\r\n\r\n⚜️ Size:\r\nS / M / L / XL\r\n\r\n⚜️ Phù hợp:\r\n✔ Đi chơi\r\n✔ Đi làm\r\n✔ Dạo phố\r\n✔ Mặc Tết cực đẹp\r\n\r\n🔥 Mẫu polo basic dễ bán – shop nào cũng nên có', 'Polo BBR bản mới 2026 – thiết kế basic sang trọng, dễ mặc dễ bán. Chất vải cao cấp, form chuẩn nam, phối túi da nổi bật cực trend.', 0, 1, 0, 0, 'Đức buôn', 'https://zalo.me/g/sscwqk872', 'uploads/img_69bacba61c3899.07412088.jpg', 1, '2026-03-18 15:58:30', NULL, '2026-03-18 15:58:30', '2026-03-20 11:08:20', 0),
(2, 'T-SHIRT LOUIS VUITTON FULL HOẠ TIẾT THÊU', 't-shirt-louis-vuitton-full-hoa-tiet-theu-ao-002', 'AO_002', 1, 1, 1, 'Nam', 425000.00, 299000.00, 225000.00, 'Đức buôn', 'Cotton, Mềm Mịn', '🔥 T-SHIRT LV – BẢN MỚI NHẤT 2026\r\n\r\nMẫu mới về cho anh em bán cực đẹp, form chuẩn – thêu full cao cấp nhìn rất sang.\r\n\r\n⚜️ Điểm nổi bật:\r\n\r\nLogo LV thêu nổi cao cấp trước ngực\r\n\r\nHọa tiết chữ Louis Vuitton thêu full sau lưng cực đẹp\r\n\r\nForm áo nam chuẩn, mặc đứng dáng\r\n\r\nChất vải cotton mềm, thoáng mát\r\n\r\n⚜️ Phong cách:\r\nBasic – nam tính – dễ phối đồ\r\nMặc đi chơi, đi làm, đi cafe đều đẹp.\r\n\r\n⚜️ Màu sắc:\r\n\r\nTrắng\r\n\r\nĐen\r\n\r\nXanh navy\r\n\r\nĐỏ đô\r\n\r\n⚜️ Size:\r\nS / M / L / XL\r\n\r\n✔ Phù hợp:\r\n\r\nĐi chơi\r\n\r\nDạo phố\r\n\r\nĐi làm\r\n\r\nMặc hằng ngày\r\n\r\n🔥 Mẫu hot dễ bán – form đẹp – logo thêu sang', 'T-Shirt LV thêu full bản mới 2026 – thiết kế nam tính, form đẹp, chất vải cao cấp, logo thêu sắc nét cực sang.', 0, 1, 0, 0, 'Đức buôn', 'https://zalo.me/g/sscwqk872', 'uploads/img_69bace5f364be7.60575138.jpg', 1, '2026-03-18 16:10:07', NULL, '2026-03-18 16:10:07', '2026-03-20 11:07:45', 0),
(3, 'T-SHIRT LOUIS VUITTON FULL HOẠ TIẾT THÊU', 't-shirt-louis-vuitton-full-hoa-tiet-theu-ao-003', 'AO_003', 1, 1, 1, 'Nam', 410000.00, 279000.00, 205000.00, 'Đức buôn', NULL, '🔥 T-SHIRT LV – HÀNG MỚI 2026\r\n\r\nMẫu mới về cho anh em bán Tết cực đẹp\r\nThiết kế trông chiến – form chuẩn – dễ bán.\r\n\r\n⚜️ Điểm nổi bật:\r\n\r\nHọa tiết thêu nổi cao cấp trước ngực\r\n\r\nPhong cách trẻ trung, cá tính\r\n\r\nForm áo nam chuẩn đẹp, mặc đứng dáng\r\n\r\nChất vải cotton mềm, thoáng mát\r\n\r\n⚜️ Màu sắc:\r\n\r\nĐen\r\n\r\nTrắng\r\n\r\n⚜️ Size:\r\nS / M / L / XL\r\n\r\n✔ Phù hợp:\r\n\r\nĐi chơi\r\n\r\nĐi làm\r\n\r\nDạo phố\r\n\r\nMặc Tết cực đẹp\r\n\r\n🔥 Mẫu basic dễ bán – nhìn là chốt đơn', 'T-Shirt LOUIS VUITTON bản mới 2026 – thiết kế trẻ trung, họa tiết thêu nổi bật, form đẹp dễ bán dịp Tết.', 0, 1, 0, 0, 'Đức buôn', 'https://zalo.me/g/sscwqk872', 'uploads/img_69bacef3567289.66223327.jpg', 1, '2026-03-18 16:12:35', NULL, '2026-03-18 16:12:35', '2026-03-20 11:06:59', 0),
(4, 'SƠ MI BURBERRY TAG ĐÁ 2 BÊN', 'so-mi-burberry-tag-da-2-ben-ao-004', 'AO_004', 1, 2, 1, 'Nam', 420000.00, 299000.00, 220000.00, 'Nhà Xung Nga', 'Cotton, Mềm Mịn', '✨ SƠ MI BBR CAO CẤP\r\n\r\nĐi tiệc – đám cưới – sự kiện thì sơ mi trắng vẫn luôn là chân ái 😍\r\n\r\nMẫu Sơ Mi BBR mới nhất với thiết kế sang trọng, điểm nhấn đính đá ở cổ áo cực nổi bật và lịch lãm.\r\n\r\n⚜️ Điểm nổi bật:\r\n\r\nForm sơ mi nam chuẩn đẹp\r\n\r\nCổ áo đính họa tiết đá sang trọng\r\n\r\nVải mềm mịn, mặc thoáng mát\r\n\r\nThiết kế thanh lịch, cực hợp đi tiệc\r\n\r\n⚜️ Màu sắc:\r\n\r\nTrắng\r\n\r\n⚜️ Size:\r\nS / M / L / XL / XXL\r\n\r\n⚜️ Phù hợp:\r\n✔ Đi tiệc\r\n✔ Đi cưới\r\n✔ Đi làm\r\n✔ Sự kiện – gặp đối tác', 'Sơ Mi Burbbery cao cấp – thiết kế lịch lãm, form chuẩn nam, cổ áo đính họa tiết nổi bật, cực phù hợp mặc tiệc – cưới – sự kiện.', 0, 1, 0, 0, 'Nhà Xung Nga', 'https://zalo.me/g/isptip699', 'uploads/img_69bad0f899b036.13945093.jpg', 1, '2026-03-18 16:21:12', NULL, '2026-03-18 16:21:12', '2026-03-18 16:21:12', 0),
(5, 'SƠ MI Dolce & Gabbana', 'so-mi-dolce-gabbana-ao-005', 'AO_005', 1, 2, 3, 'Nam', 380000.00, 260000.00, 180000.00, 'Xung Nga', 'Cotton, Mềm Mịn', '✨ SƠ MI DOLCE & GABBANA – BẢN NEW\r\n\r\nMẫu sơ mi mới về cực đẹp cho anh em bán.\r\nThiết kế lịch lãm – sang trọng – chuẩn form nam, mặc đi làm hay đi tiệc đều rất hợp.\r\n\r\n⚜️ Điểm nổi bật:\r\n\r\nLogo Dolce & Gabbana nổi bật ở cổ áo\r\n\r\nForm sơ mi nam đứng dáng\r\n\r\nChất vải mềm mịn, mặc thoáng mát\r\n\r\nThiết kế đơn giản nhưng cực sang\r\n\r\n⚜️ Màu sắc:\r\n\r\nTrắng\r\n\r\n⚜️ Size:\r\nS / M / L / XL / XXL\r\n\r\n✔ Phù hợp:\r\n\r\nĐi làm\r\n\r\nĐi tiệc\r\n\r\nĐi sự kiện\r\n\r\nGặp đối tác', 'Sơ Mi Dolce & Gabbana bản new – thiết kế sang trọng, form chuẩn nam, điểm nhấn logo cổ áo cực nổi bật.', 0, 1, 0, 0, 'Xung Nga', 'https://zalo.me/g/isptip699', 'uploads/img_69bad1f28468b7.97462758.jpg', 1, '2026-03-18 16:25:22', NULL, '2026-03-18 16:25:22', '2026-03-18 16:25:22', 0),
(6, 'SƠ MI DIOR', 'so-mi-dior-ao-006', 'AO_006', 1, 2, 1, 'Nam', 420000.00, 299000.00, 220000.00, 'Xung Nga', 'Cotton, Mềm Mịn', 'SƠ MI DIOR CAO CẤP\r\n\r\nMẫu sơ mi mới về phục vụ mùa lễ – tiệc – Tết, thiết kế đơn giản nhưng cực kỳ sang và lịch lãm.\r\n\r\n⚜️ Điểm nổi bật:\r\n\r\nTag ong Dior đính ở cổ áo tạo điểm nhấn cao cấp\r\n\r\nForm sơ mi nam chuẩn đẹp, mặc đứng dáng\r\n\r\nChất vải mềm mịn, thoáng mát\r\n\r\nPhong cách thanh lịch, dễ phối đồ\r\n\r\n⚜️ Màu sắc:\r\n\r\nTrắng\r\n\r\n⚜️ Size:\r\nS / M / L / XL / XXL\r\n\r\n✔ Phù hợp:\r\n\r\nĐi làm\r\n\r\nĐi tiệc\r\n\r\nĐi sự kiện\r\n\r\nMặc dịp lễ Tết', 'Sơ Mi Dior cao cấp – thiết kế thanh lịch, form chuẩn nam, cổ áo đính tag ong sang trọng.', 0, 1, 0, 0, 'Xung Nga', 'https://zalo.me/g/isptip699', 'uploads/img_69bad2c8c96680.21163453.jpg', 1, '2026-03-18 16:28:56', NULL, '2026-03-18 16:28:56', '2026-03-18 16:29:10', 0),
(7, 'SƠ MI MCQUEEN', 'so-mi-mcqueen-ao-007', 'AO_007', 1, 2, 1, 'Nam', 420000.00, 299000.00, 220000.00, 'Xung Nga', 'Cotton, Mềm Mịn', '✨ SƠ MI MCQ – HÀNG MỚI\r\n\r\nMẫu sơ mi mới cực đẹp dành cho anh em bán.\r\nThiết kế sang trọng – độc đáo – khác biệt, mặc lên rất nổi bật.\r\n\r\n⚜️ Điểm nổi bật:\r\n\r\nHọa tiết thêu nghệ thuật tinh xảo trước ngực\r\n\r\nPhong cách thời trang cao cấp, cá tính\r\n\r\nForm sơ mi nam chuẩn đẹp\r\n\r\nChất vải lụa cao cấp mềm mịn, mặc thoáng mát\r\n\r\n⚜️ Màu sắc:\r\n\r\nTrắng\r\n\r\n⚜️ Size:\r\nS / M / L / XL / XXL\r\n\r\n✔ Phù hợp:\r\n\r\nĐi tiệc\r\n\r\nĐi chơi\r\n\r\nSự kiện\r\n\r\nMặc dịp lễ Tết', 'Sơ Mi MCQ (McQueen) cao cấp – thiết kế họa tiết thêu tinh xảo, form chuẩn nam, phong cách sang trọng và nổi bật.', 0, 1, 0, 0, 'Xung Nga', 'https://zalo.me/g/isptip699', 'uploads/img_69bad37a4ef684.46263257.jpg', 1, '2026-03-18 16:31:54', NULL, '2026-03-18 16:31:54', '2026-03-19 01:18:07', 0);
